To implement a dictionary using a binary search tree (BST) in C++, we can create a class `Dictionary` that contains a `BinarySearchTree` to store the words and their definitions. The program will allow users to:

1. Insert words and their definitions.
2. Lookup a word and retrieve its definition.
3. Delete a word and its definition.
4. Print the entire dictionary.

Here is the C++ implementation:

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <iomanip>
#include <sstream>

using namespace std;

// Node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(const string& w, const string& d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST class
class BinarySearchTree {
public:
    BinarySearchTree() : root(nullptr) {}

    ~BinarySearchTree() {
        deleteTree(root);
    }

    void insert(const string& word, const string& definition) {
        if (root == nullptr) {
            root = new Node(word, definition);
            return;
        }

        Node* current = root;
        while (true) {
            if (word < current->word) {
                if (current->left == nullptr) {
                    current->left = new Node(word, definition);
                    break;
                }
                current = current->left;
            } else {
                if (current->right == nullptr) {
                    current->right = new Node(word, definition);
                    break;
                }
                current = current->right;
            }
        }
    }

    Node* search(const string& word) {
        Node* current = root;
        while (current != nullptr) {
            if (word == current->word) {
                return current;
            } else if (word < current->word) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        return nullptr;
    }

    void deleteNode(const string& word) {
        Node* temp = findNode(word);
        if (temp == nullptr) return;

        if (temp->left == nullptr && temp->right == nullptr) {
            delete temp;
            return;
        }

        if (temp->left && temp->right) {
            Node* leftRight = getSuccessor(temp->left);
            Node* rightLeft = getSuccessor(temp->right);

            if (leftRight) {
                // Swap with left right
                swap(temp->word, leftRight->word);
                swap(temp->definition, leftRight->definition);
                // Delete the left right node
                delete leftRight;
            } else if (rightLeft) {
                // Swap with right left
                swap(temp->word, rightLeft->word);
                swap(temp->definition, rightLeft->definition);
                // Delete the right left node
                delete rightLeft;
            } else {
                // Only one child (left or right)
                if (temp->left) {
                    Node* tempLeft = temp->left;
                    temp->word = tempLeft->word;
                    temp->definition = tempLeft->definition;
                    temp->left = tempLeft->left;
                    delete tempLeft;
                } else {
                    Node* tempRight = temp->right;
                    temp->word = tempRight->word;
                    temp->definition = tempRight->definition;
                    temp->right = tempRight->right;
                    delete tempRight;
                }
            }
        } else if (temp->left) {
            Node* tempLeft = temp->left;
            temp->word = tempLeft->word;
            temp->definition = tempLeft->definition;
            temp->left = tempLeft->left;
            delete tempLeft;
        } else {
            Node* tempRight = temp->right;
            temp->word = tempRight->word;
            temp->definition = tempRight->definition;
            temp->right = tempRight->right;
            delete tempRight;
        }
    }

    Node* findNode(const string& word) {
        Node* current = root;
        while (current != nullptr) {
            if (word == current->word) {
                return current;
            } else if (word < current->word) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        return nullptr;
    }

    Node* getSuccessor(Node* node) {
        Node* successor = node->right;
        while (successor->left != nullptr) {
            successor = successor->left;
        }
        return successor;
    }

    void deleteTree(Node* node) {
        if (node == nullptr) return;
        deleteTree(node->left);
        deleteTree(node->right);
        delete node;
    }

    void printInOrder() {
        printInOrder(root);
    }

    void printInOrder(Node* node) {
        if (node != nullptr) {
            printInOrder(node->left);
            cout << leftPad(node->word) << ": " << leftPad(node->definition) << endl;
            printInOrder(node->right);
        }
    }

    void printPreOrder() {
        printPreOrder(root);
    }

    void printPreOrder(Node* node) {
        if (node != nullptr) {
            cout << leftPad(node->word) << ": " << leftPad(node->definition) << endl;
            printPreOrder(node->left);
            printPreOrder(node->right);
        }
    }

    void printPostOrder() {
        printPostOrder(root);
    }

    void printPostOrder(Node* node) {
        if (node != nullptr) {
            printPostOrder(node->left);
            printPostOrder(node->right);
            cout << leftPad(node->word) << ": " << leftPad(node->definition) << endl;
        }
    }

private:
    Node* root;

    string leftPad(const string& s) {
        string padded;
        for (int i = 0; i < 20 - s.length(); i++) {
            padded += ' ';
        }
        return padded + s;
    }
};

class Dictionary {
public:
    BinarySearchTree bst;

    void insert(const string& word, const string& definition) {
        bst.insert(word, definition);
    }

    Node* search(const string& word) {
        return bst.search(word);
    }

    void deleteWord(const string& word) {
        bst.deleteNode(word);
    }

    void printDictionary() {
        bst.printInOrder();
    }

    void printPreDictionary() {
        bst.printPreOrder();
    }

    void printPostDictionary() {
        bst.printPostOrder();
    }
};

int main() {
    Dictionary dict;
    string word, definition;
    int choice;

    cout << "Welcome to the Dictionary App using BST!\n";
    cout << "1. Insert a word and definition\n";
    cout << "2. Lookup a word\n";
    cout << "3. Delete a word\n";
    cout << "4. Print all words and definitions\n";
    cout << "5. Print in preorder\n";
    cout << "6. Print in postorder\n";
    cout << "0. Exit\n";
    cout << "Enter your choice: ";

    while (true) {
        cin >> choice;
        if (choice == 0) {
            break;
        } else if (choice == 1) {
            cout << "Enter word: ";
            cin >> word;
            cout << "Enter definition: ";
            cin >> definition;
            dict.insert(word, definition);
            cout << "Word inserted successfully.\n";
        } else if (choice == 2) {
            cout << "Enter word to look up: ";
            cin >> word;
            Node* node = dict.search(word);
            if (node) {
                cout << "Definition: " << node->definition << endl;
            } else {
                cout << "Word not found.\n";
            }
        } else if (choice == 3) {
            cout << "Enter word to delete: ";
            cin >> word;
            dict.deleteWord(word);
            cout << "Word deleted successfully.\n";
        } else if (choice == 4) {
            dict.printDictionary();
        } else if (choice == 5) {
            dict.printPreDictionary();
        } else if (choice == 6) {
            dict.printPostDictionary();
        } else {
            cout << "Invalid choice. Please try again.\n";
        }
    }

    return 0;
}
```

### Features:
- **Insertion**: Words and definitions are inserted into the BST.
- **Search**: Words are looked up and their definitions are retrieved.
- **Deletion**: Words and their definitions are removed from the BST.
- **Printing**: The dictionary is printed in in-order, pre-order, and post-order traversal.

### Notes:
- The BST is implemented with basic operations (insert, search, delete).
- The `leftPad` function ensures that words are left-padded with spaces to maintain a consistent format.
- The program provides clear user feedback and handles invalid inputs gracefully.

