### 📦 Flutter Code Snippet (Basic Parking Finder App)

```dart
import 'package:flutter/material.dart';
import 'package:geolocator/geolocator.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

void main() {
  runApp(ParkingFinderApp());
}

class ParkingFinderApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Parking Finder',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: ParkingFinderScreen(),
    );
  }
}

class ParkingFinderScreen extends StatefulWidget {
  @override
  _ParkingFinderScreenState createState() => _ParkingFinderScreenState();
}

class _ParkingFinderScreenState extends State<ParkingFinderScreen> {
  List<ParkingSpot> parkingSpots = [];
  Position currentLocation = Position();
  bool isLoading = false;

  Future<void> getCurrentLocation() async {
    try {
      final locationResult = await Geolocator.getCurrentLocation(
        locationSettings: const LocationSettings(
          accuracy: LocationAccuracy.high,
        ),
      );
      setState(() {
        currentLocation = locationResult;
      });
    } catch (e) {
      print("Error getting location: $e");
    }
  }

  Future<void> fetchParkingSpots() async {
    setState(() {
      isLoading = true;
    });

    final url = "https://api.parkingfinder.com/v1/spots";
    final response = await http.get(Uri.parse(url), headers: {
      "Authorization": "Bearer YOUR_API_TOKEN",
    });

    if (response.statusCode == 200) {
      final List<dynamic> data = json.decode(response.body);
      setState(() {
        parkingSpots = data.map((item) => ParkingSpot.fromJson(item)).toList();
      });
    } else {
      // Handle error
      setState(() {
        parkingSpots = [];
      });
    }

    setState(() {
      isLoading = false;
    });
  }

  @override
  void initState() {
    super.initState();
    getCurrentLocation();
    fetchParkingSpots();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Parking Finder'),
      ),
      body: isLoading
          ? Center(child: CircularProgressIndicator())
          : ListView.builder(
              itemCount: parkingSpots.length,
              itemBuilder: (context, index) {
                final spot = parkingSpots[index];
                return ListTile(
                  title: Text(spot.name),
                  subtitle: Text(spot.location),
                  trailing: Icon(Icons.location_on),
                  onTap: () {
                    // Handle tap on parking spot
                    // For example, show a dialog to confirm parking
                  },
                );
              },
            ),
    );
  }
}

class ParkingSpot {
  final String name;
  final String location;
  final String status;

  ParkingSpot({required this.name, required this.location, required this.status});

  factory ParkingSpot.fromJson(Map<String, dynamic> json) {
    return ParkingSpot(
      name: json['name'],
      location: json['location'],
      status: json['status'],
    );
  }
}
