# Perl Script: Haversine Distance Calculator

This Perl script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs, handles error cases, and provides the result in kilometers or miles.

---

## 📌 Script Overview

- **Inputs**: Latitude and longitude of two locations.
- **Output**: Distance between the two locations in kilometers or miles, along with the location names.
- **Error Handling**: Validates input formats, checks for valid coordinates, and handles missing data.
- **Usage**: Run the script with two arguments (latitude1, longitude1, latitude2, longitude2).

---

## 📄 Script: `haversine.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;

# Define constants
my $KILOMETERS = 1;
my $MILES = 1;

# Define the Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371;  # Radius of the Earth in kilometers

    # Convert degrees to radians
    my $lat1_rad = radian($lat1);
    my $lon1_rad = radian($lon1);
    my $lat2_rad = radian($lat2);
    my $lon2_rad = radian($lon2);

    # Haversine formula
    my $a = sin($lat1_rad - $lat2_rad) ** 2 +
        cos($lat1_rad) * cos($lat2_rad) * sin($lat1_rad - $lat2_rad) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub radian {
    my ($degrees) = @_;
    return $degrees * pi() / 180;
}

# Get location names from a predefined list
my %locations = (
    "London" => { lat => 51.5074, lon => -0.1278 },
    "Paris" => { lat => 48.8566, lon => 2.3522 },
    "New York" => { lat => 40.7128, lon => -74.0060 },
    "Tokyo" => { lat => 35.6895, lon => 139.6917 },
);

# Main script
my $help = 0;
my $unit = $KILOMETERS;

GetOptions(
    "h" => \$help,
    "u" => \$unit,
    "k" => \$KILOMETERS,
    "m" => \$MILES,
) or die "Usage: $0 [options] <lat1> <lon1> <lat2> <lon2>";

if ($help) {
    print "Usage: $0 [options] <lat1> <lon1> <lat2> <lon2>\n";
    print "Options:\n";
    print "  -h, --help      Show this help message\n";
    print "  -u, --unit     Set unit (k=km, m=miles)\n";
    print "  -k, --kilo     Use kilometers\n";
    print "  -m, --mile     Use miles\n";
    exit;
}

# Validate input
my ($lat1, $lon1, $lat2, $lon2) = @_;
if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
    die "Error: Missing location data. Please provide 4 arguments: lat1, lon1, lat2, lon2.\n";
}

# Validate coordinates
if (!($lat1 =~ /^\-?\d+(\.\d+)?$/ || $lat1 =~ /^\-?\d+\.?\d+$/)) {
    die "Error: Invalid latitude. Please provide a valid number.\n";
}

if (!($lon1 =~ /^\-?\d+(\.\d+)?$/ || $lon1 =~ /^\-?\d+\.?\d+$/)) {
    die "Error: Invalid longitude. Please provide a valid number.\n";
}

# Check if location names are in the predefined list
my %locations_found;
foreach my $loc (qw(London Paris New York Tokyo)) {
    my $loc_data = $locations{$loc};
    if (defined $loc_data && defined $lat1 && defined $lon1 && defined $lat2 && defined $lon2) {
        if ($loc eq $lat1 && $loc eq $lon1 && $loc eq $lat2 && $loc eq $lon2) {
            $locations_found{$loc} = 1;
        }
    }
}

# If no location names match, use the input as names
my $loc1 = "Location 1";
my $loc2 = "Location 2";

# Calculate distance
my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);

# Format output
print "Distance between $loc1 and $loc2: ";
if ($unit eq $KILOMETERS) {
    print "$distance kilometers\n";
} elsif ($unit eq $MILES) {
    print "$distance miles\n";
} else {
    print "Distance in kilometers (default)\n";
}

# Print location names
print "Location 1: $loc1\n";
print "Location 2: $loc2\n";

# Print distance
print "Distance: $distance $unit\n";

# Test cases
print "\nTest Cases:\n";
print "1. London (51.5074, -0.1278) to Paris (48.8566, 2.3522) => 395.8 miles\n";
print "2. New York (40.7128, -74.0060) to Tokyo (35.6895, 139.6917) => 4158.8 kilometers\n";
