```swift
import Foundation

// Define a Node struct to represent each node in the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define a class for the BST
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, handle deletion
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node
    }

    // Helper function to find the in-order successor
    private func findInOrderSuccessor(_ node: Node?) -> Node? {
        var current = node
        var successor = nil

        // Find the in-order successor
        while current != nil {
            successor = current!
            current = current!.left
        }

        return successor
    }

    // Traversal functions
    // Pre-order traversal: visit node, then left, then right
    func preOrderTraversal() {
        preOrderTraversalHelper(root)
    }

    // Helper function for pre-order traversal
    private func preOrderTraversalHelper(_ node: Node?) {
        if node != nil {
            print("Visited: $node!.value")
            preOrderTraversalHelper(node!.left)
            preOrderTraversalHelper(node!.right)
        }
    }

    // In-order traversal: left, visit node, right
    func inOrderTraversal() {
        inOrderTraversalHelper(root)
    }

    // Helper function for in-order traversal
    private func inOrderTraversalHelper(_ node: Node?) {
        if node != nil {
            inOrderTraversalHelper(node!.left)
            print("Visited: $node!.value")
            inOrderTraversalHelper(node!.right)
        }
    }

    // Post-order traversal: left, right, visit node
    func postOrderTraversal() {
        postOrderTraversalHelper(root)
    }

    // Helper function for post-order traversal
    private func postOrderTraversalHelper(_ node: Node?) {
        if node != nil {
            postOrderTraversalHelper(node!.left)
            postOrderTraversalHelper(node!.right)
            print("Visited: $node!.value")
        }
    }
}
```

### Explanation of Key Components:

- **Node Struct**: Represents each node in the BST with a value and pointers to left and right children.
- **BinarySearchTree Class**: Manages the BST operations.
  - **insert**: Adds a new node to the correct position.
  - **delete**: Removes a node while maintaining BST properties.
  - **findInOrderSuccessor**: Helper function to find the in-order successor of a node with two children.
- **Traversal Functions**:
  - **preOrderTraversal**: Visits the node first, then left, then right.
  - **inOrderTraversal**: Left, then node, then right.
  - **postOrderTraversal**: Left, then right, then node.

### Example Usage:

```swift
let bst = BinarySearchTree()
bst.insert(5)
bst.insert(3)
bst.insert(7)
bst.insert(4)
bst.insert(6)
bst.insert(8)

print("Pre-order traversal:")
bst.preOrderTraversal()

print("\nIn-order traversal:")
bst.inOrderTraversal()

print("\nPost-order traversal:")
bst.postOrderTraversal()

bst.delete(3)
print("\nAfter deleting 3:")
bst.inOrderTraversal()
```

This implementation is efficient, with time complexity of O(log n) for insert and delete operations (in the average case), and O(n) in the worst case (e.g., when the tree is skewed).

