use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($arr1, $arr2) = @_;
    my @merged;

    # Base case: if one array is empty, return the other
    return $arr1 if @$arr1 == 0;
    return $arr2 if @$arr2 == 0;

    # Compare the first elements of both arrays
    if ($arr1->[0] >= $arr2->[0]) {
        # Add the first element of the first array to the merged array
        push @merged, $arr1->[0];
        # Recursively merge the rest of the first array with the second array
        push @merged, merge($arr1->[1..-1], $arr2);
    } else {
        # Add the first element of the second array to the merged array
        push @merged, $arr2->[0];
        # Recursively merge the rest of the second array with the first array
        push @merged, merge($arr1, $arr2->[1..-1]);
    }

    return @merged;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr == 0;

    # Base case: if the array has only one element, return it
    return $arr if @$arr == 1;

    # Split the array into two halves
    my $mid = int(@$arr / 2);
    my $left = $arr->[0..$mid - 1];
    my $right = $arr->[$mid..-1];

    # Recursively sort both halves
    my $left_sorted = merge_sort($left);
    my $right_sorted = merge_sort($right);

    # Merge the two sorted halves
    my $merged = merge($left_sorted, $right_sorted);

    return $merged;
}

# Main program
print "Enter integers separated by spaces (end with 'exit' to quit):\n";

while (1) {
    chomp(my $input = <STDIN>);
    last if $input eq 'exit';

    # Check if input is empty
    if ($input eq '') {
        print "Please enter valid integers.\n";
        next;
    }

    # Split input into an array of integers
    my @nums = map { $_ } split(/\s+/, $input);
    my $valid = 1;

    # Check for invalid input (non-integer values)
    foreach my $num (@nums) {
        if (!($num =~ /^\d+$/)) {
            print "Invalid input: $num. Please enter integers only.\n";
            $valid = 0;
            last;
        }
    }

    if ($valid) {
        # Sort the array in descending order using merge sort
        my $sorted = merge_sort(\@nums);
        print "Sorted array in descending order:\n";
        print join(" ", @$sorted), "\n";
    } else {
        print "Invalid input. Please try again.\n";
    }
}
```

### Explanation:

- **Merge Sort Algorithm**: The `merge_sort` function recursively splits the array into halves, sorts them, and merges them back in sorted order.
- **Merge Function**: The `merge` function merges two sorted arrays into one sorted array in descending order.
- **Input Handling**: The program reads input from the user, validates it, and handles edge cases like empty input or invalid values.
- **Output**: The sorted array is printed in descending order.

